1993	  \uses{lem:S3_pi_1_Gamma_baseChange_iso_tensor_of_proper}
1994	  \leanok
1995	  Smoothness of $X / \Spec k$ implies that for any field extension $K / k$ the base change $X_K$ is reduced (smooth $\Rightarrow$ formally smooth $\Rightarrow$ geometrically reduced fibres; Stacks Tags~\textbf{0334} + \textbf{04QM}). The global-section ring $\Gamma(X_K, \mathcal O_{X_K})$ injects into the stalks of $X_K$ at its points (sheaf separatedness on a reduced source), each of which is reduced; hence $\Gamma(X_K, \mathcal O_{X_K})$ is itself reduced as a $K$-algebra. By the flat-base-change identification \cref{lem:S3_pi_1_Gamma_baseChange_iso_tensor_of_proper} (whose content is the same as path (a) step~(e) of the proof of \cref{lem:constants_integral_over_base_field}, just re-packaged as a single named lemma), $\Gamma(X, \mathcal O_X) \otimes_k K \cong \Gamma(X_K, \mathcal O_{X_K})$ is reduced for every field extension $K / k$. That is, $\Gamma(X, \mathcal O_X)$ is geometrically reduced over $k$. Estimated build: $\sim 80$--$150$ LOC.
1996	
1997	  \emph{Literature.} Stacks Tag~\textbf{0334} (smoothness $\Rightarrow$ formally smooth); Stacks Tag~\textbf{04QM} (smooth morphisms have geometrically reduced fibres); Hartshorne III.10 (smoothness and reducedness).
1998	\end{proof}
1999	
2000	\begin{lemma}
2001	[(S3.sep.2) Geometrically reduced finite field extension is separable]
2002	  \label{lem:S3_sep_2_geom_reduced_finite_field_ext_is_separable}
2003	  \lean{Algebra.IsSeparable.of_isGeometricallyReduced_of_finite}
2004	  \uses{lem:S3_sep_1_smooth_geometrically_reduced_Gamma}
2005	  Let $F / k$ be a finite field extension of fields. If $F$ is geometrically reduced as a $k$-algebra (\texttt{Algebra.IsGeometricallyReduced}\,$k$\,$F$, equivalently $F \otimes_k \bar k$ is reduced), then $F / k$ is separable (\texttt{Algebra.IsSeparable}\,$k$\,$F$).
2006	
2007	  This sub-claim is the (S3.sep.2) closer of path (b)'s separability strand: the (S3.sep.1) gateway delivers geometric reducedness of $\Gamma(X, \mathcal O_X)$ over $k$; combined with finite-field-extension structure (from steps (a)--(d) of path (a) applied at the geometric level), this lemma upgrades geometric reducedness to separability of the finite field extension $\Gamma(X, \mathcal O_X) / k$.
2008	\end{lemma}
2009	
2010	\begin{proof}
2011	  \uses{lem:S3_sep_1_smooth_geometrically_reduced_Gamma}
2012	  By definition \texttt{Algebra.IsGeometricallyReduced}\,$k$\,$F$ says $F \otimes_k \bar k$ is reduced. Since $F / k$ is finite, $F \otimes_k \bar k$ is a finite-dimensional $\bar k$-algebra, hence Artinian, and decomposes uniquely as a finite product $F \otimes_k \bar k \cong \prod_i F_i$ of Artinian local $\bar k$-algebras at its (finitely many) minimal primes. Reducedness of the product forces each Artinian local factor $F_i$ to be a field, finite over $\bar k$; algebraic closedness of $\bar k$ then forces $F_i = \bar k$.
2013	
2014	  Therefore $F \otimes_k \bar k \cong \bar k^{r}$ for $r = \#\{\text{minimal primes of } F \otimes_k \bar k\}$. The $\bar k$-dimension on both sides gives $[F : k] = \dim_{\bar k}(F \otimes_k \bar k) = r$. On the other hand, $r$ equals the number of distinct $k$-algebra embeddings $F \hookrightarrow \bar k$ (the closed points of $\Spec(F \otimes_k \bar k)$). The equality $[F : k] = \#\{\text{embeddings } F \hookrightarrow \bar k\}$ is precisely the criterion for separability of a finite field extension. Estimated build: $\sim 30$--$50$ LOC.
2015	
2016	  \emph{Literature.} Stacks Tag~\textbf{0BJF} (``a field extension is separable iff its base change to the algebraic closure is reduced''); Bourbaki \emph{Alg\`ebre} Chap.~V \S 15 N$^\circ$ 3 (separability criteria via tensor products with $\bar k$).
2017	\end{proof}
2018	
2019	\begin{lemma}
2020	
2021	\leanok
2022	[(S3.pi.1) Flat base change of $\Gamma$ for proper schemes]
2023	  \label{lem:S3_pi_1_Gamma_baseChange_iso_tensor_of_proper}
2024	  \lean{AlgebraicGeometry.Gamma_baseChange_iso_tensor_of_proper}
2025	  Let $X$ be a proper scheme over a field $k$, and let $K / k$ be a field extension. Then the canonical comparison map
2026	  \[
2027	    \Gamma(X, \mathcal O_X) \otimes_k K \;\xrightarrow{\;\sim\;}\; \Gamma(X_K, \mathcal O_{X_K})
2028	  \]
2029	  is an isomorphism of $K$-algebras, where $X_K := X \times_{\Spec k} \Spec K$ is the base change of $X$ along $\Spec K \to \Spec k$. This is the specialisation of ``cohomology along proper morphisms commutes with flat base change'' (Stacks Tag~\textbf{02KH}) to the $H^0 = \Gamma$ row.
2030	
2031	  This sub-claim is the (S3.pi.1) load-bearing substep of path (b) of the proof of \cref{lem:constants_integral_over_base_field}. Its content is the same content as path (a) step~(e), packaged as a single named lemma request rather than as a 7-step ad-hoc chain scattered across $\Gamma_{\bar k}$-cohomology infrastructure.
2032	\end{lemma}
2033	
2034	\begin{proof}
2035	
2036	\leanok
2037	  Cover $X$ by finitely many affine opens $U_i = \Spec A_i$ (quasi-compactness from properness). The \v Cech complex on the cover $\{U_i\}$ computes $\Gamma(X, \mathcal O_X)$ as the equalizer
2038	  \[
2039	    \Gamma(X, \mathcal O_X) \;=\; \mathrm{eq}\bigl(\textstyle\prod_i A_i \rightrightarrows \prod_{i, j} A_{ij}\bigr) \qquad \text{where } A_{ij} := \Gamma(U_i \cap U_j, \mathcal O_X).
2040	  \]
2041	  Tensoring with $K$ over $k$ preserves equalizers (flatness of $K$ as a $k$-module). Chart-by-chart, the affine-side flat-base-change isomorphism $A_i \otimes_k K \cong \Gamma((U_i)_K, \mathcal O_{(U_i)_K})$ holds by Stacks Tag~\textbf{00DS} (flat base change for affines), and similarly for the intersections $A_{ij} \otimes_k K \cong \Gamma((U_i \cap U_j)_K, \mathcal O)$ (each $U_i \cap U_j$ is itself quasi-affine and admits a finite affine cover whose flat-base-change identification reassembles to the intersection's flat-base-change isomorphism). Reassembling chart-by-chart with the same \v Cech equalizer description on the base-changed cover $\{(U_i)_K\}$ identifies $\Gamma(X, \mathcal O_X) \otimes_k K$ with $\Gamma(X_K, \mathcal O_{X_K})$. Estimated build: $\sim 150$--$250$ LOC (the dominant cost is the \v Cech equaliser + flat-tensor exchange chase, plus the verification that the affine intersection flat-base-change isomorphism reassembles to the global comparison).
2042	
2043	  \emph{Honesty note.} The content of this lemma is the SAME content as path~(a) step~(e) of the 7-step chain in the proof of \cref{lem:constants_integral_over_base_field}, not bypassed by the smart-proof path~(b). Path~(b)'s genuine advantage is that it re-packages the flat-base-change content as ONE named Mathlib lemma request, rather than as a 7-step ad-hoc chain scattered across $\Gamma_{\bar k}$-cohomology infrastructure. See \texttt{references/literature-crosscheck-iter149.md} \S Target~1 (``$\beta$-aux constants''), bullet ``Implication for iter-149+ plan'', for the literature-cross-check finding.
2044	
2045	  \emph{Literature.} Stacks Tag~\textbf{02KH} (cohomology along proper morphisms commutes with flat base change); Stacks Tag~\textbf{0AY8} (integral closure descends under flat base change); Hartshorne III.9.3 (flat base change of cohomology, the $H^0$ row).
2046	\end{proof}
